// Despachar tarea Celery de scraping de fichas
const API_URL = 'https://api-auditor.sekaitech.com.pe';

let result;
try {
  result = await this.helpers.httpRequest({
    method: 'POST',
    url: API_URL + '/api/v1/scraper/fichas/start?agreement_code=EXT-CE-2022-5',
    headers: { 'Accept': 'application/json' },
    json: true,
    timeout: 15000
  });
  if (typeof result === 'string') result = JSON.parse(result);
} catch(e) {
  return [{ json: { error: true, message: e.message } }];
}

if (!result.task_id) {
  return [{ json: { error: true, message: result.error || 'No se recibio task_id del backend' } }];
}

return [{ json: result }];

// Polling de estado hasta que la tarea Celery termine (SUCCESS o FAILURE)
// Tiempo maximo: 16 intentos x 60s = ~16 minutos
const API_URL = 'https://api-auditor.sekaitech.com.pe';
const task_id = $input.first().json.task_id;
const MAX_ATTEMPTS = 16;
const WAIT_MS = 60000;

let lastResp = { status: 'TIMEOUT', error: 'La tarea supero el tiempo maximo de espera (16 minutos)' };

for (let i = 0; i < MAX_ATTEMPTS; i++) {
  await new Promise(resolve => setTimeout(resolve, WAIT_MS));
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: API_URL + '/api/v1/scraper/status/' + task_id,
      headers: { 'Accept': 'application/json' },
      json: true,
      timeout: 15000
    });
    lastResp = (typeof resp === 'string') ? JSON.parse(resp) : resp;
    const st = lastResp.status;
    if (st === 'SUCCESS' || st === 'FAILURE') break;
  } catch(e) {
    lastResp = { status: 'FAILURE', error: e.message };
    break;
  }
}

return [{ json: lastResp }];

// Notificar error via Evolution API
const EVOLUTION_URL      = 'https://evolution.sekaitech.com.pe';
const EVOLUTION_API_KEY  = '6mF28RqtJdPIZorVIbAaRBiKZoZr3a5t4d9jikNna7c=';
const EVOLUTION_INSTANCE = 'sekaitech';
const GROUP_JID          = '120363423813951789@g.us';

const inp = $input.item.json;
const errorMsg = inp.message || inp.error || 'Error desconocido';
const ahora = new Date().toLocaleString('es-PE', { timeZone: 'America/Lima' });

const texto = [  '\u26a0\ufe0f *ERROR \u2014 CEAM Auditor Scraper (Fichas)*',  '\ud83d\uddd3\ufe0f ' + ahora,  '\u2500'.repeat(34),  'El proceso de extraccion de catalogo fallo.',  '',  'Error: ' + errorMsg,  '',  'Revisa los logs en el contenedor del backend.'].join('\n');

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: EVOLUTION_URL + '/message/sendText/' + EVOLUTION_INSTANCE,
    headers: { 'apikey': EVOLUTION_API_KEY, 'Content-Type': 'application/json' },
    body: { number: GROUP_JID, text: texto },
    json: true,
    timeout: 10000
  });
} catch(e) {}

return [{ json: { notified: true, error: String(errorMsg) } }];

// Construir mensajes agrupados por marca desde deltas_suspendidas
// El resultado Celery viene en: .result.deltas_suspendidas
const data = $input.first().json;
const deltas = (data.result && data.result.deltas_suspendidas) ? data.result.deltas_suspendidas : [];

if (!deltas || deltas.length === 0) {
  return [{ json: { hayAlertas: 'false', mensajes: [], total: 0 } }];
}

const sep = '\u2500'.repeat(30);
const totalSuspendidas = deltas.length;

// Agrupar por marca
const byMarca = {};
for (const f of deltas) {
  const marca = (f.marca || 'OTRAS').toUpperCase();
  if (!byMarca[marca]) byMarca[marca] = [];
  byMarca[marca].push(f);
}

const partes = [
  '\u26a0\ufe0f *ALERTAS DE CATALOGO: FICHAS SUSPENDIDAS*',
  '\ud83d\uddd3\ufe0f ' + new Date().toLocaleString('es-PE', { timeZone: 'America/Lima' }),
  sep,
  '\ud83d\udea8 El escaner detecto ' + totalSuspendidas + ' ficha(s) suspendida(s):'
];

for (const [marca, fichas] of Object.entries(byMarca)) {
  partes.push('\n\ud83c\udfec *MARCA: ' + marca + '*');
  fichas.forEach(function(f, i) {
    partes.push('   \u274c *' + (i + 1) + '.* P/N: *' + f.nro_parte + '*');
    if (f.descripcion) partes.push('      \u21b3 ' + f.descripcion);
  });
}

partes.push('\n' + sep + '\n\ud83e\udd16 _CEAM Auditor Automatico_');

return [{ json: { hayAlertas: 'true', mensajes: [partes.join('\n')], total: totalSuspendidas } }];

// ENVIAR VIA EVOLUTION API -> GRUPO WHATSAPP CEAM
const EVOLUTION_URL      = 'https://evolution.sekaitech.com.pe';
const EVOLUTION_API_KEY  = '6mF28RqtJdPIZorVIbAaRBiKZoZr3a5t4d9jikNna7c=';
const EVOLUTION_INSTANCE = 'sekaitech';
const GROUP_JID          = '120363423813951789@g.us';

let results = [];

for (const item of $input.all()) {
  const mensaje = item.json.mensaje || '';
  if (!mensaje) continue;

  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: EVOLUTION_URL + '/message/sendText/' + EVOLUTION_INSTANCE,
      headers: { 'apikey': EVOLUTION_API_KEY, 'Content-Type': 'application/json' },
      body: { number: GROUP_JID, text: mensaje },
      json: true,
      timeout: 15000
    });
    results.push({ json: { success: true, key: r.key } });
    await new Promise(resolve => setTimeout(resolve, 1500));
  } catch(e) {
    results.push({ json: { success: false, error: e.message } });
  }
}

return results;
